 *
 * @param nodeName Name for the node to update
 * @return bool Whether transactional update succeeded (no cycle created)
 */
bool test_transactional_update(const std::string& nodeName) {
    // 1. Create observer nodes
    auto nodeA = std::make_shared<TestTransactionalObserver>("A_" + nodeName);
    auto nodeB = std::make_shared<TestTransactionalObserver>("B_" + nodeName);

    // 2. Get observer graph instance
    auto& graph = reaction::ObserverGraph::getInstance();

    // 3. Set up initial relationship (A -> B: when A changes, B is notified)
    graph.addObserver(nodeA, nodeB);

    // 4. Notify target and verify relationship works
    nodeA->valueChanged(true);

    // Verify B was notified through the relationship
    if (!nodeB->wasChanged() || nodeB->getCallCount() != 1) {
        return false;
    }

    // 5. Reset observer for next test
    nodeA->reset();
    nodeB->reset();

    // 6. Attempt transactional update that would create cycle
    // Try to add B -> A which would create a cycle (A->B->A)
    bool cycleDetected = false;
    try {
        graph.addObserver(nodeB, nodeA);
    } catch (const std::exception& e) {
        // 7. Catch cycle exception if thrown
        cycleDetected = true;
    }

    // 8. Notify target again
    nodeA->valueChanged(true);

    // 9. Verify original relationship is preserved
    // B should still be notified when A changes
    if (!nodeB->wasChanged() || nodeB->getCallCount() != 1) {
        return false;
    }

    // Verify no reverse relationship was created (A should not be in a cycle)
    // If a cycle was created, notifying A would cause it to be notified again
    // Since we only called valueChanged once, callCount should be 1
    if (nodeA->getCallCount() != 1) {
        return false;
    }

    // 10. Return success status
    // Success means cycle was detected and prevented, and original relationship preserved
    return cycleDetected;
}

}  // namespace test_reaction
