    // 9. Get value after bitwise AND
    int afterBitwiseAnd = calc.value();

    // 10. Apply atomic left shift
    counter <<= 2;

    // 11. Get value after shift
    int afterShift = calc.value();

    // 12. Apply post-increment
    int postIncrementReturn = counter++;

    // 13. Get final value
    int finalValue = calc.value();

    // 14. Return atomic compound snapshot
    return AtomicCompoundSnapshot{
        afterAddition,
        afterMultiplication,
        afterBitwiseAnd,
        afterShift,
        postIncrementReturn,
        finalValue,
        calcEvaluations
    };
