    // Step 11-12: Apply atomic increment and check if it reported change
    reaction::atomicIncrement(impl);
    snapshot.incrementReportedChange = impl.lastReportedChange();

    // Step 13: Get final value
    snapshot.finalValue = impl.value();

    // Step 14: Return atomic helper snapshot
    return snapshot;
}

}  // namespace test_reaction
